INSERT INTO "T_COST_PAGE_RULE" ("ID", "PAGE_CODE", "COMPONENT_KEY", "RULE_TYPE", "RULES", "SORT_ORDER", "DESCRIPTION", "DELETED", "CREATE_TIME", "UPDATE_TIME", "CREATE_BY", "UPDATE_BY") VALUES (475, 'cost-pinggu', 'masterGrid', 'CALC', TO_CLOB('[{"field":"SALEMONEY","expression":"CostPinggu.OUT_PRICE_RMB / CostPinggu.P_PERPACK * CostPinggu.APEX_PL * (CostPinggu.YIELD / 100)","triggerFields":["CostPinggu.OUT_PRICE_RMB","CostPinggu.P_PERPACK","CostPinggu.APEX_PL","CostPinggu.YIELD"]},{"field":"JGF_BATCH","expression":"CostPinggu.SALEMONEY - CostPinggu.TOTAL_COST","triggerFields":["CostPinggu.SALEMONEY","CostPinggu.TOTAL_COST"]},{"field":"COST_PERBOX","expression":"CostPinggu.TOTAL_COST / CostPinggu.APEX_PL * CostPinggu.P_PERPACK","triggerFields":["CostPinggu.TOTAL_COST","CostPinggu.APEX_PL","CostPinggu.P_PERPACK"]},{"field":"JGF_PERQP","expression":"CostPinggu.JGF_BATCH / CostPinggu.APEX_PL * 1000","triggerFields":["CostPinggu.JGF_BATCH","CostPinggu.APEX_PL"]},{"field":"ML_PERQP","expression":"CostPinggu.JGF_PERQP - CostPinggu.COST_PERQP","triggerFields":["CostPinggu.JGF_PERQP","CostPinggu.COST_PERQP"]},{"field":"Y_JG_RE","expression":"CostPinggu.JGF_PERQP / 1000 * CostPinggu.ANNUAL_QTY","triggerFields":["CostPinggu.JGF_PERQP","CostPinggu.ANNUAL_QTY"]},{"field":"Y_ML","expression":"CostPinggu.ML_PERQP / 1000 * CostPinggu.ANNUAL_QTY","triggerFields":["CostPinggu.ML_PERQP","CostPinggu.ANNUAL_QTY"]},{"field":"Y_SALE","expression":"CostPinggu.ANNUAL_QTY / CostPinggu.P_PERPACK * CostPinggu.OUT_PRICE_RMB * CostPinggu.YIELD","triggerFields":["CostPinggu.ANNUAL_QTY","CostPinggu.P_PERPACK","CostPinggu.OUT_PRICE_RMB","CostPinggu.YIELD"]},{"field":"TOTAL_YL","expression":"SUM_IF(''CostMaterial.COST_BATCH'', \"CostMaterial.DTL_USEFLAG == ''原料''\") * (SUM_IF(''CostMaterial.COST_BATCH'', \"CostMaterial.DTL_USEFLAG == ''原料''\") > 0 ? 1 / 1.13 : 1)","triggerFields":["CostMaterial.COST_BATCH","CostMaterial.DTL_USEFLAG"]},{"field":"TOTAL_FL","expression":"SUM_IF(''CostMaterial.COST_BATCH'', \"CostMaterial.DTL_USEFLAG == ''辅料''\") * (SUM_IF(''CostMaterial.COST_BATCH'', \"CostMaterial.DTL_USEFLAG == ''原料''\") > 0 ? 1 / 1.13 : 1)","triggerFields":["CostMaterial.COST_BATCH","CostMaterial.DTL_USEFLAG"],"order":9},{"field":"TOTAL_BC","expression":"SUM_IF(''CostPackage.COST_BATCH'', \"CostPackage.DTL_USEFLAG == ''印字包材'' || CostPackage.DTL_USEFLAG == ''非印字包材''\") * (SUM_IF(''CostMaterial.COST_BATCH'', \"CostMaterial.DTL_USEFLAG == ''原料''\") > 0 ? 1 / 1.13 : 1)","triggerFields":["CostPackage.COST_BATCH","CostPackage.DTL_USEFLAG","CostMaterial.COST_BATCH","CostMaterial.DTL_USEFLAG"],"order":10},{"field":"TOTAL_COST","expression":"CostPinggu.TOTAL_YL + CostPinggu.TOTAL_FL + CostPinggu.TOTAL_BC","triggerFields":["CostPinggu.TOTAL_YL","CostPinggu.TOTAL_FL","CostPinggu.TOTAL_BC"],"order":11}]'), 0, NULL, 0, TO_TIMESTAMP('2026-01-28 17:27:10.872', 'YYYY-MM-DD HH24:MI:SS.FF'), TO_TIMESTAMP('2026-03-04 10:13:04.671', 'YYYY-MM-DD HH24:MI:SS.FF'), 'system', NULL);
